SELECT
	COUNT(*) AS cnt
FROM
	ELIB_CATEGORY
WHERE
	delete_yn = 'N'
AND depth = #{depth}
AND type = #{type}

AND parent_id = #{parent_id}


AND cate_id = #{cate_id}

SELECT
	cate_id, cate_name, depth, display_seq, parent_id, type
FROM
	ELIB_CATEGORY
WHERE
	delete_yn = 'N'
AND depth = #{depth}
AND type = #{type}

AND parent_id = #{parent_id}


AND cate_id = #{cate_id}

ORDER BY display_seq

SELECT
	a.cate_id, a.cate_name, a.depth, a.display_seq, a.parent_id, a.type,
	(
		SELECT COUNT(*)
		FROM ELIB_BOOK b
		WHERE b.use_yn != 'N'
		AND a.type = b.type


		AND a.cate_id = b.cate_id
		AND b.parent_id = #{parent_id}


		AND a.cate_id = b.parent_id



		AND b.approved_yn = #{approved_yn}

	) AS cnt
FROM
	ELIB_CATEGORY a
WHERE
	delete_yn = 'N'
AND depth = #{depth}
AND type = #{type}

AND parent_id = #{parent_id}


AND cate_id = #{cate_id}

ORDER BY display_seq

SELECT
a.cate_id, a.cate_name, a.depth, a.display_seq, a.parent_id, a.type,
(
SELECT COUNT(*)
FROM ELIB_HOPE_BOOK b
WHERE b.use_yn != 'N'
AND b.application_status IS NULL
AND a.type = b.type

	AND	UPPER(REPLACE(b.book_name, ' ')) LIKE '%'||UPPER(REPLACE(#{search_text}, ' '))||'%'



		AND a.cate_id = b.cate_id
		AND b.parent_id = #{parent_id}


		AND a.cate_id = b.parent_id



	AND b.approved_yn = #{approved_yn}

) AS cnt
FROM
ELIB_CATEGORY a
